#include<bits/stdc++.h>
using namespace std;
long long b[500010];
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long fstl,ll,num;
    }t[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(node &x,node ls,node rs)
    {
        if(!rs.fstl&&!rs.ll)
        {
            x.fstl=ls.fstl;
            x.ll=ls.ll;
            x.num=ls.num;
            return;
        }
        if(!ls.fstl&&!ls.ll)
        {
            x.fstl=rs.fstl;
            x.ll=rs.ll;
            x.num=rs.num;
            return;
        }
        if(ls.ll>rs.fstl)
        {
            x.fstl=ls.fstl;
            x.ll=ls.ll-rs.fstl+rs.ll;
            x.num=((ls.num>>rs.fstl)<<rs.ll)+rs.num;
        }
        else
        {
            x.fstl=ls.fstl+rs.fstl-ls.ll;
            x.ll=rs.ll;
            x.num=rs.num;
        }
    }
    void pushup(long long x)
    {
        pushup(t[x],t[t[x].lson],t[t[x].rson]);
    }
    void push(long long x,long long v)
    {
        if(v==1)
        {
            t[x].num=t[x].fstl=0;
            t[x].ll=1;
        }
        else if(v==2)
        {
            t[x].fstl=0;
            t[x].ll=t[x].num=1;
        }
        else
        {
            t[x].fstl=1;
            t[x].ll=t[x].num=0;
        }
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        t[x].l=l;
        t[x].r=r;
        if(l==r)
        {
            push(x,b[l]);
            return x;
        }
        long long mid=(l+r)>>1;
        t[x].lson=init(l,mid);
        t[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,long long v)
    {
        if(t[x].l>p||t[x].r<p)
        {
            return;
        }
        if(t[x].l==t[x].r)
        {
            push(x,v);
            return;
        }
        update(t[x].lson,p,v);
        update(t[x].rson,p,v);
        pushup(x);
    }
    node query(long long x,long long l,long long r)
    {
        if(l<=t[x].l&&t[x].r<=r)
        {
            return t[x];
        }
        long long mid=(t[x].l+t[x].r)>>1;
        if(l<=mid&&r>mid)
        {
            node ans=t[x];
            pushup(ans,query(t[x].lson,l,r),query(t[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(t[x].lson,l,r);
        }
        else
        {
            return query(t[x].rson,l,r);
        }
    }
}t;
int main()
{
    long long n,m,q;
    scanf("%lld%lld%lld",&n,&m,&q);
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,m);
    while(q--)
    {
        long long op,x,y,s,l,r;
        scanf("%lld",&op);
        if(op==1)
        {
            scanf("%lld%lld%lld",&s,&l,&r);
            auto p=t.query(1,l,r);
            s=(max(1ll,s>>p.fstl)<<p.ll)+p.num;
            printf("%lld\n",s);
        }
        else
        {
            scanf("%lld%lld",&x,&y);
            t.update(1,x,y);
        }
    }
    return 0;
}
